L23: 
L24:     @Override
L25:     public Node createView() {
L26:         TextArea input  = styledTextArea("Paste JSON......");
L27:         TextArea output = styledTextArea("");
L28:         output.setEditable(false);
L29: 
L30:         Button formatBtn  = actionButton("Format",  "#5b8cf7");
L31:         Button compactBtn = actionButton("Compact", "rgba(255,255,255,0.12)");
L32:         Button clearBtn   = actionButton("Clear",   "rgba(255,255,255,0.08)");
L33: 
L34:         formatBtn.setOnAction(e -> {
