L64:     private String prettyPrint(String json) {
L65:         StringBuilder sb = new StringBuilder();
L66:         int indent = 0;
L67:         boolean inString = false;
L68:         for (char c : json.toCharArray()) {
L69:             if (c == '"' && (sb.isEmpty() || sb.charAt(sb.length() - 1) != '\\'))
L70:                 inString = !inString;
L71:             if (!inString) {
L72:                 if (c == '{' || c == '[') {
L73:                     sb.append(c).append('\n');
L74:                     indent += 2;
L75:                     sb.append(" ".repeat(indent));
L76:                     continue;
L77:                 } else if (c == '}' || c == ']') {
L78:                     sb.append('\n');
L79:                     indent = Math.max(0, indent - 2);
L80:                     sb.append(" ".repeat(indent)).append(c);
L81:                     continue;
L82:                 } else if (c == ',') {
L83:                     sb.append(c).append('\n').append(" ".repeat(indent));
L84:                     continue;
L85:                 } else if (c == ':') {
L86:                     sb.append(": ");
L87:                     continue;
L88:                 } else if (c == ' ' || c == '\n' || c == '\r' || c == '\t') {
L89:                     continue;
L90:                 }
L91:             }
L92:             sb.append(c);
L93:         }
L94:         return sb.toString();
L95:     }
L96: 
L97:     private static TextArea styledTextArea(String prompt) {
L98:         TextArea ta = new TextArea();
L99:         ta.setPromptText(prompt);
L100:         ta.setStyle(
L101:             "-fx-background-color: rgba(255,255,255,0.04);" +
L102:             "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
L103:             "-fx-border-radius: 10; -fx-background-radius: 10;" +
L104:             "-fx-text-fill: rgba(255,255,255,0.88);" +
L105:             "-fx-font-size: 13px; -fx-font-family: 'SF Mono','Consolas',monospace;" +
L106:             "-fx-control-inner-background: transparent; -fx-highlight-fill: #5b8cf7;" +
L107:             "-fx-padding: 12;"
L108:         );
L109:         ta.setWrapText(true);
L110:         VBox.setVgrow(ta, Priority.ALWAYS);
L111:         return ta;
L112:     }
L113: 
L114:     private static Button actionButton(String text, String bg) {
L115:         Button btn = new Button(text);
L116:         btn.setStyle(
L117:             "-fx-background-color: " + bg + ";" +
L118:             "-fx-text-fill: rgba(255,255,255,0.88); -fx-font-size: 13px;" +
L119:             "-fx-background-radius: 8; -fx-border-width: 0;" +
L120:             "-fx-padding: 8 18 8 18; -fx-cursor: hand;"
L121:         );
L122:         return btn;
L123:     }
L124: 
L125:     private static Label sectionLabel(String text) {
L126:         Label l = new Label(text.toUpperCase());
L127:         l.setStyle(
L128:             "-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 10px;" +
L129:             "-fx-font-weight: bold; -fx-letter-spacing: 0.08em;"
L130:         );
L131:         return l;
L132:     }
L133: }
