L21: public class HashCalculatorPlugin implements SwissKitJPlugin {
L22: 
L23:     private static final String[][] ALGOS = {
L24:         {"MD5", "MD5"}, {"SHA-1", "SHA-1"}, {"SHA-256", "SHA-256"}, {"SHA-512", "SHA-512"}
L25:     };
L26: 
L27:     @Override public String getId()          { return "builtin.hash"; }
L28:     @Override public String getName()        { return "Hash Calculator"; }
L29:     @Override public String getDescription() { return "MD5 / SHA-1 / SHA-256 / SHA-512"; }
L30:     @Override public String getCategory()    { return "dev"; }
L31:     @Override public String getVersion()     { return "1.0.0"; }
L32:     @Override public String getMdiIcon()    { return "key-variant"; }
L33:     @Override public String getIconStyle()   { return "ic-amber"; }
L34:     @Override public String getType()        { return "builtin"; }
