L36:     @Override
L37:     public Node createView() {
L38:         TextArea input = styledTextArea("Input text...");
L39:         VBox results   = new VBox(8);
L40: 
L41:         Button calcBtn = actionButton("Calculate Hash", "#5b8cf7");
L42:         calcBtn.setOnAction(e -> {
L43:             results.getChildren().clear();
L44:             for (String[] algo : ALGOS) {
L45:                 try {
L46:                     MessageDigest md   = MessageDigest.getInstance(algo[1]);
L47:                     byte[]        hash = md.digest(input.getText().getBytes(StandardCharsets.UTF_8));
L48:                     StringBuilder hex  = new StringBuilder();
L49:                     for (byte b : hash) hex.append(String.format("%02x", b));
L50:                     results.getChildren().add(hashRow(algo[0], hex.toString()));
L51:                 } catch (Exception ex) {
L52:                     results.getChildren().add(hashRow(algo[0], "Error"));
L53:                 }
L54:             }
L55:         });
L56: 
L57:         VBox root = new VBox(12, sectionLabel("Input Text"), input, calcBtn, sectionLabel("Result"), results);
L58:         VBox.setVgrow(input, Priority.ALWAYS);
L59:         root.setPadding(new Insets(20));
L60:         root.setStyle("-fx-background-color: transparent;");
L61:         return root;
L62:     }
