L65:         Label algoLabel = new Label(algo);
L66:         algoLabel.setStyle(
L67:             "-fx-text-fill: rgba(255,255,255,0.45); -fx-font-size: 11px;" +
L68:             "-fx-min-width: 60px; -fx-font-family: 'SF Mono','Consolas',monospace;"
L69:         );
L70:         Label valueLabel = new Label(value);
