L72:             "-fx-text-fill: rgba(255,255,255,0.85); -fx-font-size: 11px;" +
L73:             "-fx-font-family: 'SF Mono','Consolas',monospace;"
L74:         );
L75:         valueLabel.setMaxWidth(Double.MAX_VALUE);
L76:         HBox.setHgrow(valueLabel, Priority.ALWAYS);
L77: 
L78:         Button copy = new Button("Copy");
