L80:             "-fx-background-color: rgba(255,255,255,0.08); -fx-border-width: 0;" +
L81:             "-fx-text-fill: rgba(255,255,255,0.5); -fx-font-size: 10px;" +
L82:             "-fx-background-radius: 4; -fx-cursor: hand; -fx-padding: 2 8 2 8;"
L83:         );
L84:         copy.setOnAction(e -> {
L85:             ClipboardContent cc = new ClipboardContent();
L86:             cc.putString(value);
L87:             Clipboard.getSystemClipboard().setContent(cc);
L88:             copy.setText("✓");
L89:             PauseTransition pt = new PauseTransition(Duration.seconds(1.5));
L90:             pt.setOnFinished(ev -> copy.setText("Copy"));
L91:             pt.play();
L92:         });
L93: 
L94:         HBox row = new HBox(10, algoLabel, valueLabel, copy);
L95:         row.setAlignment(Pos.CENTER_LEFT);
L96:         row.setStyle(
L97:             "-fx-background-color: rgba(255,255,255,0.04);" +
L98:             "-fx-background-radius: 8; -fx-padding: 10 12 10 12;"
L99:         );
L100:         return row;
L101:     }
