L13: public class MarkdownEditorPlugin implements SwissKitJPlugin {
L14: 
L15:     @Override public String getId()          { return "builtin.markdown"; }
L16:     @Override public String getName()        { return "Markdown"; }
L17:     @Override public String getDescription() { return "Real-time Markdown editor with preview"; }
L18:     @Override public String getCategory()    { return "text"; }
L19:     @Override public String getVersion()     { return "1.0.0"; }
L20:     @Override public String getMdiIcon()    { return "language-markdown"; }
L21:     @Override public String getIconStyle()   { return "ic-blue"; }
L22:     @Override public String getType()        { return "builtin"; }
L23: 
L24:     @Override
L25:     public Node createView() {
L26:         TextArea editor = styledTextArea(
L27:             "# Hello SwissKitJ\n\n" +
L28:             "This is a **Markdown** editor.\n\n" +
L29:             "- Supports *italic* and **bold**\n" +
L30:             "- Supports lists\n" +
L31:             "- Supports `code`\n\n" +
L32:             "> Quote text\n"
L33:         );
L34: 
L35:         WebView preview = new WebView();
L36:         preview.setStyle("-fx-background-color: transparent;");
L37: 
L38:         Runnable render = () -> {
L39:             String html = mdToHtml(editor.getText());
L40:             String page =
L41:                 "<html><head><style>" +
L42:                 "body{font-family:-apple-system,sans-serif;color:rgba(255,255,255,0.88);" +
L43:                 "background:transparent;padding:16px;font-size:14px;line-height:1.7;}" +
L44:                 "code{background:rgba(255,255,255,0.1);border-radius:4px;padding:2px 6px;" +
L45:                 "font-family:monospace;}" +
L46:                 "blockquote{border-left:3px solid #5b8cf7;margin:0;padding-left:16px;" +
L47:                 "color:rgba(255,255,255,0.5);}" +
L48:                 "h1,h2,h3{color:rgba(255,255,255,0.95);}" +
L49:                 "</style></head><body>" + html + "</body></html>";
L50:             preview.getEngine().loadContent(page);
L51:         };
L52: 
L53:         editor.textProperty().addListener((o, oldV, newV) -> render.run());
L54: 
L55:         VBox left  = new VBox(6, sectionLabel("Editor"),  editor);
L56:         VBox right = new VBox(6, sectionLabel("Preview"), preview);
L57:         VBox.setVgrow(editor,   Priority.ALWAYS);
L58:         VBox.setVgrow(preview,  Priority.ALWAYS);
L59:         HBox.setHgrow(left,  Priority.ALWAYS);
L60:         HBox.setHgrow(right, Priority.ALWAYS);
L61: 
L62:         HBox root = new HBox(12, left, right);
L63:         root.setPadding(new Insets(20));
L64:         root.setStyle("-fx-background-color: transparent;");
L65:         HBox.setHgrow(root, Priority.ALWAYS);
L66:         VBox.setVgrow(root, Priority.ALWAYS);
L67:         render.run();
L68:         return root;
L69:     }
L70: 
L71:     private String mdToHtml(String md) {
L72:         return md
L73:             .replaceAll("(?m)^### (.+)$", "<h3>$1</h3>")
L74:             .replaceAll("(?m)^## (.+)$",  "<h2>$1</h2>")
L75:             .replaceAll("(?m)^# (.+)$",   "<h1>$1</h1>")
L76:             .replaceAll("\\*\\*(.+?)\\*\\*", "<strong>$1</strong>")
L77:             .replaceAll("\\*(.+?)\\*",        "<em>$1</em>")
L78:             .replaceAll("`(.+?)`",            "<code>$1</code>")
L79:             .replaceAll("(?m)^> (.+)$",       "<blockquote>$1</blockquote>")
L80:             .replaceAll("(?m)^- (.+)$",       "<li>$1</li>")
L81:             .replaceAll("(?m)^$",             "<br/>");
L82:     }
