L85:         TextArea ta = new TextArea(initial);
L86:         ta.setStyle(
L87:             "-fx-background-color: rgba(255,255,255,0.04);" +
L88:             "-fx-border-color: rgba(255,255,255,0.10); -fx-border-width: 1;" +
L89:             "-fx-border-radius: 10; -fx-background-radius: 10;" +
L90:             "-fx-text-fill: rgba(255,255,255,0.88);" +
L91:             "-fx-font-size: 13px; -fx-font-family: 'SF Mono','Consolas',monospace;" +
L92:             "-fx-control-inner-background: transparent; -fx-highlight-fill: #5b8cf7;" +
L93:             "-fx-padding: 12;"
L94:         );
L95:         ta.setWrapText(true);
L96:         VBox.setVgrow(ta, Priority.ALWAYS);
L97:         return ta;
L98:     }
L99: 
L100:     private static Label sectionLabel(String text) {
L101:         Label l = new Label(text.toUpperCase());
L102:         l.setStyle(
L103:             "-fx-text-fill: rgba(255,255,255,0.28); -fx-font-size: 10px;" +
L104:             "-fx-font-weight: bold; -fx-letter-spacing: 0.08em;"
L105:         );
L106:         return l;
L107:     }
L108: }
