L261:     private List<String> splitAddresses(String raw) {
L262:         List<String> out = new ArrayList<>();
L263:         if (raw == null) return out;
L264:         for (String part : raw.split("[,;\\s]+")) {
L265:             String trimmed = part.trim();
L266:             if (!trimmed.isEmpty()) out.add(trimmed);
L267:         }
L268:         return out;
L269:     }
