L193:             task.setOnSucceeded(e -> {
L194:                 config.analysisResult = task.getValue();
L195:                 analysisRunning.set(false);
L196:                 showLoading(false);
L197:                 int sheetCount = config.analysisResult.size();
L198:                 statusLabel.setText("✓ 共 " + sheetCount + " 个Sheet：" +
L199:                     config.analysisResult.keySet().stream().limit(5).collect(Collectors.joining(", ")) +
L200:                     (sheetCount > 5 ? " …" : ""));
