L136:     private List<StorePlugin> fetchPlugins(String urlStr) throws Exception {
L137:         HttpURLConnection conn = (HttpURLConnection) new URL(urlStr).openConnection();
L138:         conn.setRequestMethod("GET");
L139:         conn.setConnectTimeout(10000);
L140:         conn.setReadTimeout(15000);
L141:         conn.setRequestProperty("Accept", "application/json");
L142: 
L143:         int responseCode = conn.getResponseCode();
L144:         if (responseCode != 200) {
L145:             throw new RuntimeException("HTTP " + responseCode);
L146:         }
L147: 
L148:         StringBuilder sb = new StringBuilder();
L149:         try (BufferedReader br = new BufferedReader(new InputStreamReader(conn.getInputStream()))) {
L150:             String line;
L151:             while ((line = br.readLine()) != null) {
L152:                 sb.append(line);
L153:             }
L154:         }
L155: 
L156:         return parsePluginJson(sb.toString());
L157:     }
L158: 
L159:     private List<StorePlugin> parsePluginJson(String json) {
L160:         List<StorePlugin> result = new ArrayList<>();
L161:         // Simple JSON parser for the plugin list array
L162:         // Expected format: [{ "id": "...", "name": "...", "description": "...", "version": "...", "jarUrl": "...", "iconStyle": "...", "category": "..." }, ...]
L163:         try {
L164:             // Find array start
L165:             int arrayStart = json.indexOf('[');
L166:             int arrayEnd = json.lastIndexOf(']');
L167:             if (arrayStart == -1 || arrayEnd == -1) return result;
L168: 
L169:             String arrayContent = json.substring(arrayStart + 1, arrayEnd);
L170:             // Split by }{ (avoiding full regex for safety)
L171:             String[] objects = arrayContent.split("\\},\\s*\\{");
L172: 
L173:             for (String obj : objects) {
L174:                 if (!obj.startsWith("{")) obj = "{" + obj;
L175:                 if (!obj.endsWith("}")) obj = obj + "}";
L176: 
L177:                 StorePlugin p = new StorePlugin();
L178:                 p.id = extractJsonString(obj, "id");
L179:                 p.name = extractJsonString(obj, "name");
L180:                 p.description = extractJsonString(obj, "description");
L181:                 p.version = extractJsonString(obj, "version");
L182:                 p.jarUrl = extractJsonString(obj, "jarUrl");
L183:                 p.iconStyle = extractJsonString(obj, "iconStyle", "ic-blue");
L184:                 p.category = extractJsonString(obj, "category", "other");
L185: 
L186:                 if (p.id != null && p.name != null && p.jarUrl != null) {
L187:                     result.add(p);
L188:                 }
L189:             }
L190:         } catch (Exception e) {
L191:             log.warn("JSON parse error, showing partial results", e);
L192:         }
L193:         return result;
L194:     }
L195: 
L196:     private String extractJsonString(String json, String key) {
L197:         return extractJsonString(json, key, null);
L198:     }
L199: 
L200:     private String extractJsonString(String json, String key, String defaultVal) {
L201:         String search = "\"" + key + "\"";
L202:         int keyPos = json.indexOf(search);
L203:         if (keyPos == -1) return defaultVal;
L204: 
L205:         int colonPos = json.indexOf(':', keyPos);
L206:         if (colonPos == -1) return defaultVal;
L207: 
L208:         int valueStart = json.indexOf('"', colonPos + 1);
L209:         if (valueStart == -1) return defaultVal;
L210: 
L211:         int valueEnd = json.indexOf('"', valueStart + 1);
L212:         if (valueEnd == -1) return defaultVal;
L213: 
L214:         return json.substring(valueStart + 1, valueEnd);
L215:     }
