L308:     private void installPlugin(StorePlugin plugin, Button installBtn, ProgressBar progress) {
L309:         installBtn.setDisable(true);
L310:         progress.setVisible(true);
L311:         progress.setProgress(-1);
L312:         final ProgressBar finalProgress = progress;
L313: 
L314:         new Thread(() -> {
L315:             try {
L316:                 Path pluginDir = Path.of(System.getProperty("user.dir"), "plugins");
L317:                 Files.createDirectories(pluginDir);
L318: 
L319:                 // Download JAR
L320:                 HttpURLConnection conn = (HttpURLConnection) new URL(plugin.jarUrl).openConnection();
L321:                 conn.setConnectTimeout(15000);
L322:                 conn.setReadTimeout(30000);
L323: 
L324:                 int responseCode = conn.getResponseCode();
L325:                 if (responseCode != 200) {
L326:                     throw new RuntimeException("Download failed: HTTP " + responseCode);
L327:                 }
L328: 
L329:                 final String jarFileName;
L330:                 String extractedName = plugin.jarUrl.substring(plugin.jarUrl.lastIndexOf('/') + 1);
L331:                 if (extractedName.toLowerCase().endsWith(".jar")) {
L332:                     jarFileName = extractedName;
L333:                 } else {
L334:                     jarFileName = plugin.id.replace('.', '-') + ".jar";
L335:                 }
L336:                 Path target = pluginDir.resolve(jarFileName);
L337: 
L338:                 // Stream to file
L339:                 try (var in = conn.getInputStream();
L340:                      var out = new FileOutputStream(target.toFile())) {
L341:                     byte[] buffer = new byte[8192];
L342:                     int bytesRead;
L343:                     long total = 0;
L344:                     long contentLength = conn.getContentLengthLong();
L345:                     while ((bytesRead = in.read(buffer)) != -1) {
L346:                         out.write(buffer, 0, bytesRead);
L347:                         total += bytesRead;
L348:                         if (contentLength > 0) {
L349:                             double progressVal = (double) total / contentLength;
L350:                             Platform.runLater(() -> finalProgress.setProgress(progressVal));
L351:                         }
L352:                     }
L353:                 }
L354: 
L355:                 log.info("Plugin downloaded and installed: {}", target);
L356: 
L357:                 Platform.runLater(() -> {
L358:                     progress.setProgress(1.0);
L359:                     statusLabel.setText("✓ Installed: " + plugin.name + " → " + jarFileName);
L360:                     statusLabel.setStyle("-fx-text-fill: #4cd97b; -fx-font-size: 12px;");
L361:                     installBtn.setDisable(false);
L362:                     if (onInstallComplete != null) onInstallComplete.run();
L363:                 });
L364:             } catch (Exception ex) {
L365:                 log.error("Plugin install failed for {}", plugin.id, ex);
L366:                 Platform.runLater(() -> {
L367:                     progress.setVisible(false);
L368:                     showError("Install failed: " + ex.getMessage());
L369:                     installBtn.setDisable(false);
L370:                 });
L371:             }
L372:         }).start();
L373:     }
