L1: package fan.summer.plugin;
L2: 
L3: import fan.summer.api.SwissKitJPlugin;
L4: import javafx.collections.FXCollections;
L5: import javafx.collections.ObservableList;
L6: import org.slf4j.Logger;
L7: import org.slf4j.LoggerFactory;
L8: 
L9: import java.util.List;
L10: 
L11: /**
L12:  * Holds the live plugin list and manages plugin activation lifecycle.
L13:  * Built-in tools are added directly via getPlugins().addAll();
L14:  * external JAR plugins are added/removed by PluginLoader.
L15:  */
L16: public class PluginRegistry {
L17: 
L18:     private static final Logger log = LoggerFactory.getLogger(PluginRegistry.class);
L19: 
L20:     private final ObservableList<SwissKitJPlugin> plugins =
L21:         FXCollections.observableArrayList();
L22: 
L23:     private SwissKitJPlugin activePlugin;
L24: 
L25:     public PluginRegistry(PluginLoader loader) {
L26:         loader.setRegistry(this);
L27:     }
L28: 
L29:     // ── Plugin list ──────────────────────────────────────────────
L30: 
L31:     public ObservableList<SwissKitJPlugin> getPlugins() {
L32:         return plugins;
L33:     }
L34: 
L35:     // Called by PluginLoader (already on FX thread via Platform.runLater)
L36:     void addPlugins(List<SwissKitJPlugin> toAdd) {
L37:         log.debug("Adding {} plugin(s) to registry", toAdd.size());
L38:         plugins.addAll(toAdd);
L39:     }
L40: 
L41:     // Called by PluginLoader (already on FX thread via Platform.runLater)
L42:     void removePlugin(SwissKitJPlugin plugin) {
L43:         log.debug("Removing plugin from registry: id={}", plugin.getId());
L44:         if (activePlugin == plugin) {
L45:             try {
L46:                 plugin.onDeactivate();
L47:             } catch (Exception e) {
L48:                 log.warn("Plugin {} threw on onDeactivate(): {}", plugin.getId(), e.getMessage(), e);
L49:             }
L50:             activePlugin = null;
L51:         }
L52:         try {
L53:             plugin.onUnload();
L54:         } catch (Exception e) {
L55:             log.warn("Plugin {} threw on onUnload(): {}", plugin.getId(), e.getMessage(), e);
L56:         }
L57:         plugins.remove(plugin);
L58:     }
L59: 
L60:     // ── Lifecycle ────────────────────────────────────────────────
L61: 
L62:     /**
L63:      * Activate a plugin: deactivates the currently active one first.
L64:      */
L65:     public void activate(SwissKitJPlugin plugin) {
L66:         if (activePlugin != null && activePlugin != plugin) {
L67:             log.debug("Deactivating previous plugin: id={}", activePlugin.getId());
L68:             try {
L69:                 activePlugin.onDeactivate();
L70:             } catch (Exception e) {
L71:                 log.warn("Plugin {} threw on onDeactivate(): {}", activePlugin.getId(), e.getMessage(), e);
L72:             }
L73:         }
L74:         activePlugin = plugin;
L75:         log.info("Activating plugin: id={}, name={}", plugin.getId(), plugin.getName());
L76:         try {
L77:             plugin.onActivate();
L78:         } catch (Exception e) {
L79:             log.warn("Plugin {} threw on onActivate(): {}", plugin.getId(), e.getMessage(), e);
L80:         }
L81:     }
L82: 
L83:     public SwissKitJPlugin getActivePlugin() {
L84:         return activePlugin;
L85:     }
L86: 
L87:     public void deactivate() {
L88:         if (activePlugin != null) {
L89:             log.debug("Deactivating plugin: id={}", activePlugin.getId());
L90:             try {
L91:                 activePlugin.onDeactivate();
L92:             } catch (Exception e) {
L93:                 log.warn("Plugin {} threw on onDeactivate(): {}", activePlugin.getId(), e.getMessage(), e);
L94:             }
L95:             activePlugin = null;
L96:         }
L97:     }
L98: }
